diff --git a/__tests__/components/Collapsible-test.js b/__tests__/components/Collapsible-test.js
new file mode 100644
index 0000000..0113378
--- /dev/null
+++ b/__tests__/components/Collapsible-test.js
@@ -0,0 +1,20 @@
+// (C) Copyright 2014-2016 Hewlett Packard Enterprise Development LP
+
+import React from 'react';
+import renderer from 'react/lib/ReactTestRenderer';
+
+import Collapsible from '../../src/js/components/Collapsible';
+
+// needed because this:
+// https://github.com/facebook/jest/issues/1353
+jest.mock('react-dom');
+
+describe('Collapsible', () => {
+  it('has correct default options', () => {
+    const component = renderer.create(
+      <Collapsible />
+    );
+    let tree = component.toJSON();
+    expect(tree).toMatchSnapshot();
+  });
+});

