diff --git a/src/js/components/Box/__tests__/Box-test.js b/src/js/components/Box/__tests__/Box-test.js
new file mode 100644
index 0000000..8c1f068
--- /dev/null
+++ b/src/js/components/Box/__tests__/Box-test.js
@@ -0,0 +1,317 @@
+import React from 'react';
+import renderer from 'react-test-renderer';
+import 'jest-styled-components';
+
+import { Grommet } from '../../Grommet';
+import { Box } from '../';
+
+test('Box renders', () => {
+  const component = renderer.create(
+    <Grommet>
+      <Box />
+    </Grommet>
+  );
+  const tree = component.toJSON();
+  expect(tree).toMatchSnapshot();
+});
+
+test('Box direction renders', () => {
+  const component = renderer.create(
+    <Grommet>
+      <Box direction='row' />
+      <Box direction='column' />
+    </Grommet>
+  );
+  const tree = component.toJSON();
+  expect(tree).toMatchSnapshot();
+});
+
+test('Box reverse renders', () => {
+  const component = renderer.create(
+    <Grommet>
+      <Box reverse={true} />
+      <Box reverse={false} />
+    </Grommet>
+  );
+  const tree = component.toJSON();
+  expect(tree).toMatchSnapshot();
+});
+
+// test('Box responsive renders', () => {
+//   const component = renderer.create(
+//     <Grommet>
+//       <Box responsive={true} />
+//       <Box responsive={false} />
+//     </Grommet>
+//   );
+//   const tree = component.toJSON();
+//   expect(tree).toMatchSnapshot();
+// });
+
+test('Box wrap renders', () => {
+  const component = renderer.create(
+    <Grommet>
+      <Box wrap={true} />
+      <Box wrap={false} />
+    </Grommet>
+  );
+  const tree = component.toJSON();
+  expect(tree).toMatchSnapshot();
+});
+
+test('Box justify renders', () => {
+  const component = renderer.create(
+    <Grommet>
+      <Box justify='start' />
+      <Box justify='center' />
+      <Box justify='between' />
+      <Box justify='end' />
+    </Grommet>
+  );
+  const tree = component.toJSON();
+  expect(tree).toMatchSnapshot();
+});
+
+test('Box align renders', () => {
+  const component = renderer.create(
+    <Grommet>
+      <Box align='start' />
+      <Box align='center' />
+      <Box align='baseline' />
+      <Box align='stretch' />
+      <Box align='end' />
+    </Grommet>
+  );
+  const tree = component.toJSON();
+  expect(tree).toMatchSnapshot();
+});
+
+test('Box alignContent renders', () => {
+  const component = renderer.create(
+    <Grommet>
+      <Box alignContent='start' />
+      <Box alignContent='center' />
+      <Box alignContent='between' />
+      <Box alignContent='around' />
+      <Box alignContent='stretch' />
+      <Box alignContent='end' />
+    </Grommet>
+  );
+  const tree = component.toJSON();
+  expect(tree).toMatchSnapshot();
+});
+
+test('Box alignSelf renders', () => {
+  const component = renderer.create(
+    <Grommet>
+      <Box alignSelf='start' />
+      <Box alignSelf='center' />
+      <Box alignSelf='stretch' />
+      <Box alignSelf='end' />
+    </Grommet>
+  );
+  const tree = component.toJSON();
+  expect(tree).toMatchSnapshot();
+});
+
+test('Box justifySelf renders', () => {
+  const component = renderer.create(
+    <Grommet>
+      <Box justifySelf='start' />
+      <Box justifySelf='center' />
+      <Box justifySelf='stretch' />
+      <Box justifySelf='end' />
+    </Grommet>
+  );
+  const tree = component.toJSON();
+  expect(tree).toMatchSnapshot();
+});
+
+test('Box textAlign renders', () => {
+  const component = renderer.create(
+    <Grommet>
+      <Box textAlign='start' />
+      <Box textAlign='center' />
+      <Box textAlign='end' />
+    </Grommet>
+  );
+  const tree = component.toJSON();
+  expect(tree).toMatchSnapshot();
+});
+
+test('Box background renders', () => {
+  const component = renderer.create(
+    <Grommet>
+      <Box background='brand' />
+      <Box background='accent-1' />
+      <Box background='neutral-1' />
+      <Box background='light-1' />
+      <Box background='dark-1' />
+      <Box background='status-critical' />
+      <Box background='url(data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAMAAAADCAYAAABWKLW/AAAABGdBTUEAALGPC/xhBQAAAA9JREFUCB1jYMAC/mOIAQASFQEAlwuUYwAAAABJRU5ErkJggg==)' />
+      <Box
+        background={{
+          image: 'url(data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAMAAAADCAYAAABWKLW/AAAABGdBTUEAALGPC/xhBQAAAA9JREFUCB1jYMAC/mOIAQASFQEAlwuUYwAAAABJRU5ErkJggg==)',
+          dark: false,
+        }}
+      />
+      <Box
+        background={{
+          image: 'url(data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAMAAAADCAYAAABWKLW/AAAABGdBTUEAALGPC/xhBQAAAA9JREFUCB1jYMAC/mOIAQASFQEAlwuUYwAAAABJRU5ErkJggg==)',
+          dark: true,
+        }}
+      />
+    </Grommet>
+  );
+  const tree = component.toJSON();
+  expect(tree).toMatchSnapshot();
+});
+
+test('Box basis renders', () => {
+  const component = renderer.create(
+    <Grommet>
+      <Box>
+        <Box basis='xsmall' />
+        <Box basis='small' />
+        <Box basis='medium' />
+        <Box basis='large' />
+        <Box basis='xlarge' />
+      </Box>
+      <Box direction='row'>
+        <Box basis='full' />
+      </Box>
+      <Box direction='row'>
+        <Box basis='1/2' />
+        <Box basis='1/2' />
+      </Box>
+      <Box direction='row'>
+        <Box basis='1/3' />
+        <Box basis='2/3' />
+      </Box>
+      <Box direction='row'>
+        <Box basis='1/4' />
+        <Box basis='3/4' />
+      </Box>
+    </Grommet>
+  );
+  const tree = component.toJSON();
+  expect(tree).toMatchSnapshot();
+});
+
+test('Box flex renders', () => {
+  const component = renderer.create(
+    <Grommet>
+      <Box>
+        <Box flex={true} />
+        <Box flex={false} />
+        <Box flex='grow' />
+        <Box flex='shrink' />
+      </Box>
+    </Grommet>
+  );
+  const tree = component.toJSON();
+  expect(tree).toMatchSnapshot();
+});
+
+test('Box full renders', () => {
+  const component = renderer.create(
+    <Grommet>
+      <Box>
+        <Box full={true} />
+        <Box full={false} />
+        <Box full='horizontal' />
+        <Box full='vertical' />
+        <Box full='grow' />
+      </Box>
+    </Grommet>
+  );
+  const tree = component.toJSON();
+  expect(tree).toMatchSnapshot();
+});
+
+test('Box margin renders', () => {
+  const component = renderer.create(
+    <Grommet>
+      <Box margin='small' />
+      <Box margin='medium' />
+      <Box margin='large' />
+      <Box margin={{ horizontal: 'small' }} />
+      <Box margin={{ vertical: 'small' }} />
