+          <Box id='1' pad='medium' />
+          <Box id='2' pad='medium' />
+        </Box>
+        <Diagram connections={[{ fromId: '1', toId: '2' }]} />
+      </Stack>
+    </Grommet>
+  );
+  const tree = component.toJSON();
+  expect(tree).toMatchSnapshot();
+});

