+
+test('renders size', () => {
+  const component = renderer.create(
+    <Grommet>
+      {['xxsmall', 'xsmall', 'small', 'medium', 'large', 'xlarge', 'full'].map(size => (
+        <RangeSelector key={size} size={size} values={[20, 30]} />
+      ))}
+    </Grommet>
+  );
+  const tree = component.toJSON();
+  expect(tree).toMatchSnapshot();
+});
+
+test('renders step', () => {
