+      jest.advanceTimersByTime(DEBOUNCE_TIMEOUT);
+    });
+    expect(onView).toHaveBeenNthCalledWith(
+      2,
+      expect.objectContaining({
+        search: 'a',
+        page: 1,
+      }),
+    );
+
+    fireEvent.change(searchBox, {
+      target: { value: '' },
+    });
+    act(() => {
+      jest.advanceTimersByTime(DEBOUNCE_TIMEOUT);
+    });
+    expect(onView).toHaveBeenNthCalledWith(
+      3,
+      expect.objectContaining({
+        search: '',
+        page: 1,
+      }),
+    );
+  });
 });

