--- /dev/null
+++ b/src/js/components/FormField/__tests__/FormField-test.tsx
@@ -0,0 +1,594 @@
+import { fireEvent, render, screen, waitFor } from '@testing-library/react';
+import { axe } from 'jest-axe';
+import 'jest-axe/extend-expect';
+import 'jest-styled-components';
+import React from 'react';
+import 'regenerator-runtime/runtime';
+import styled from 'styled-components';
+
+import { Alert, New, StatusInfo } from 'grommet-icons';
+import { FormField } from '..';
+import { CheckBox } from '../../CheckBox';
+import { Form } from '../../Form';
+import { Grommet } from '../../Grommet';
+import { TextInput } from '../../TextInput';
+import { TextArea } from '../../TextArea';
+import { Text } from '../../Text';
+
+const CustomFormField = styled(FormField)`
+  font-size: 40px;
+`;
+
+describe('FormField', () => {
+  test(`should have no accessibility violations`, async () => {
+    const { container } = render(
+      <Grommet>
+        <FormField />
+      </Grommet>,
+    );
+    const results = await axe(container);
+    expect(container.firstChild).toMatchSnapshot();
+    expect(results).toHaveNoViolations();
+  });
+
+  test('default', () => {
+    const { container } = render(
+      <Grommet>
+        <FormField />
+        <FormField>
+          <TextInput />
+        </FormField>
+      </Grommet>,
+    );
+
+    expect(container.firstChild).toMatchSnapshot();
+  });
+
+  test('default outside grommet wrapper', () => {
+    const { container } = render(<FormField />);
+
+    expect(container.firstChild).toMatchSnapshot();
+  });
+
+  test('label', () => {
+    const { container } = render(
+      <Grommet>
+        <FormField label="test label" />
+      </Grommet>,
+    );
+
+    expect(container.firstChild).toMatchSnapshot();
+  });
+
+  test('help', () => {
+    const { container } = render(
+      <Grommet>
+        <FormField help="test help" />
+      </Grommet>,
+    );
+
